 906     // operand 0
 907     unsigned Idx = CI->getZExtValue();
 908     auto *EE = cast<ExtractElementInst>(E);
 909     const unsigned VF = ::getNumElements(EE->getVectorOperandType());
 910     if (Idx >= VF)
