14398             !R.areAllUsersVectorized(cast<Instruction>(V), &VectorizedVals) ||
14399             any_of(VEs,
14400                    [&](const TreeEntry *TE) {
14401                      return R.DeletedNodes.contains(TE) ||
14402                             R.TransformedToGatherNodes.contains(TE);
14403                    }) ||
14404             (E->UserTreeIndex && E->UserTreeIndex.EdgeIdx == UINT_MAX &&
14405              !R.isVectorized(EE) &&
14406              count_if(E->Scalars, [&](Value *V) { return V == EE; }) !=
14407                  count_if(E->UserTreeIndex.UserTE->Scalars,
14408                           [&](Value *V) { return V == EE; })) ||
14409             any_of(EE->users(),
14410                    [&](User *U) {
14411                      return isa<GetElementPtrInst>(U) &&
14412                             !R.areAllUsersVectorized(cast<Instruction>(U),
14413                                                      &VectorizedVals);
14414                    }) ||
14415             (!VEs.empty() && !is_contained(VEs, E)))
14416           continue;
14417         std::optional<unsigned> EEIdx = getExtractIndex(EE);
14418         if (!EEIdx)
14419           continue;
14420         unsigned Idx = *EEIdx;
14421         // Take credit for instruction that will become dead.
14422         if (EE->hasOneUse() || !PrevNodeFound) {
14423           Instruction *Ext = EE->user_back();
14424           if (isa<SExtInst, ZExtInst>(Ext) &&
14425               all_of(Ext->users(), IsaPred<GetElementPtrInst>)) {
14426             // Use getExtractWithExtendCost() to calculate the cost of
14427             // extractelement/ext pair.
14428             Cost -= TTI.getExtractWithExtendCost(
14429                 Ext->getOpcode(), Ext->getType(), EE->getVectorOperandType(),
14430                 Idx, CostKind);
14431             // Add back the cost of s|zext which is subtracted separately.
14432             Cost += TTI.getCastInstrCost(
14433                 Ext->getOpcode(), Ext->getType(), EE->getType(),
14434                 TTI::getCastContextHint(Ext), CostKind, Ext);
14435             continue;
14436           }
14437         }
14438         APInt &DemandedElts =
14439             VectorOpsToExtracts
14440                 .try_emplace(VecBase,
14441                              APInt::getZero(getNumElements(VecBase->getType())))
14442                 .first->getSecond();
14443         DemandedElts.setBit(Idx);
14444       }
14445     }
14446     for (const auto &[Vec, DemandedElts] : VectorOpsToExtracts)
14447       Cost -= TTI.getScalarizationOverhead(cast<VectorType>(Vec->getType()),
14448                                            DemandedElts, /*Insert=*/false,
14449                                            /*Extract=*/true, CostKind);
14450     // Check that gather of extractelements can be represented as just a
14451     // shuffle of a single/two vectors the scalars are extracted from.
14452     // Found the bunch of extractelement instructions that must be gathered
14453     // into a vector and can be represented as a permutation elements in a
14454     // single input vector or of 2 input vectors.
14455     // Done for reused if same extractelements were vectorized already.
14456     if (!PrevNodeFound)
14457       Cost += computeExtractCost(VL, Mask, ShuffleKinds, NumParts);
14458     InVectors.assign(1, E);
14459     CommonMask.assign(Mask.begin(), Mask.end());
14460     transformMaskAfterShuffle(CommonMask, CommonMask);
14461     SameNodesEstimated = false;
14462     if (NumParts != 1 && UniqueBases.size() != 1) {
14463       UseVecBaseAsInput = true;
14464       VecBase =
14465           Constant::getNullValue(getWidenedType(ScalarTy, CommonMask.size()));
14466     }
14467     return VecBase;
14468   }
14469   /// Checks if the specified entry \p E needs to be delayed because of its
14470   /// dependency nodes.
14471   std::optional<InstructionCost>
14472   needToDelay(const TreeEntry *,
14473               ArrayRef<SmallVector<const TreeEntry *>>) const {
14474     // No need to delay the cost estimation during analysis.
14475     return std::nullopt;
14476   }
14477   /// Reset the builder to handle perfect diamond match.
14478   void resetForSameNode() {
14479     IsFinalized = false;
14480     CommonMask.clear();
14481     InVectors.clear();
14482     Cost = 0;
14483     VectorizedVals.clear();
14484     SameNodesEstimated = true;
14485   }
14486   void add(const TreeEntry &E1, const TreeEntry &E2, ArrayRef<int> Mask) {
14487     if (&E1 == &E2) {
14488       assert(all_of(Mask,
14489                     [&](int Idx) {
14490                       return Idx < static_cast<int>(E1.getVectorFactor());
14491                     }) &&
14492              "Expected single vector shuffle mask.");
14493       add(E1, Mask);
14494       return;
14495     }
14496     if (InVectors.empty()) {
14497       CommonMask.assign(Mask.begin(), Mask.end());
14498       InVectors.assign({&E1, &E2});
14499       return;
14500     }
14501     assert(!CommonMask.empty() && "Expected non-empty common mask.");
14502     auto *MaskVecTy = getWidenedType(ScalarTy, Mask.size());
14503     unsigned NumParts = ::getNumberOfParts(TTI, MaskVecTy, Mask.size());
14504     unsigned SliceSize = getPartNumElems(Mask.size(), NumParts);
14505     const auto *It = find_if(Mask, not_equal_to(PoisonMaskElem));
14506     unsigned Part = std::distance(Mask.begin(), It) / SliceSize;
14507     estimateNodesPermuteCost(E1, &E2, Mask, Part, SliceSize);
14508   }
14509   void add(const TreeEntry &E1, ArrayRef<int> Mask) {
14510     if (InVectors.empty()) {
14511       CommonMask.assign(Mask.begin(), Mask.end());
14512       InVectors.assign(1, &E1);
14513       return;
14514     }
14515     assert(!CommonMask.empty() && "Expected non-empty common mask.");
14516     auto *MaskVecTy = getWidenedType(ScalarTy, Mask.size());
14517     unsigned NumParts = ::getNumberOfParts(TTI, MaskVecTy, Mask.size());
14518     unsigned SliceSize = getPartNumElems(Mask.size(), NumParts);
14519     const auto *It = find_if(Mask, not_equal_to(PoisonMaskElem));
14520     unsigned Part = std::distance(Mask.begin(), It) / SliceSize;
14521     estimateNodesPermuteCost(E1, nullptr, Mask, Part, SliceSize);
14522     if (!SameNodesEstimated && InVectors.size() == 1)
14523       InVectors.emplace_back(&E1);
14524   }
14525   /// Adds 2 input vectors and the mask for their shuffling.
14526   void add(Value *V1, Value *V2, ArrayRef<int> Mask) {
14527     // May come only for shuffling of 2 vectors with extractelements, already
14528     // handled in adjustExtracts.
14529     assert(InVectors.size() == 1 &&
14530            all_of(enumerate(CommonMask),
14531                   [&](auto P) {
14532                     if (P.value() == PoisonMaskElem)
14533                       return Mask[P.index()] == PoisonMaskElem;
14534                     auto *EI = cast<ExtractElementInst>(
14535                         cast<const TreeEntry *>(InVectors.front())
14536                             ->getOrdered(P.index()));
14537                     return EI->getVectorOperand() == V1 ||
14538                            EI->getVectorOperand() == V2;
14539                   }) &&
14540            "Expected extractelement vectors.");
14541   }
14542   /// Adds another one input vector and the mask for the shuffling.
14543   void add(Value *V1, ArrayRef<int> Mask, bool ForExtracts = false) {
14544     if (InVectors.empty()) {
14545       assert(CommonMask.empty() && !ForExtracts &&
14546              "Expected empty input mask/vectors.");
14547       CommonMask.assign(Mask.begin(), Mask.end());
14548       InVectors.assign(1, V1);
14549       return;
